Okay, let's walk through setting up an S3 bucket using AWS CDK to store customer financial records. This example will cover the basic setup, including configuring encryption, versioning, and access control.

**Prerequisites:**

*   **AWS Account:** You'll need an active AWS account.
*   **CDK Installed:**  Make sure you have the AWS CDK installed and configured.  Follow the instructions here: [https://docs.aws.cdk.js.org/cdk/latest/gettingstarted/installation-tutorial/index.html](https://docs.aws.cdk.js.org/cdk/latest/gettingstarted/installation-tutorial/index.html)
*   **AWS CLI Configured:**  The AWS CLI should be configured with your credentials.

**Code Example (TypeScript):**

```typescript
import * as cdk from 'aws-cdk-lib';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as iam from 'aws-cdk-lib/aws-iam';

export class CustomerFinancialRecordsBucketStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create an S3 bucket
    const bucket = new s3.Bucket(this, 'CustomerFinancialRecordsBucket', {
      bucketName: 'customer-financial-records-' + this.node.id, // Unique bucket name
      removalPolicy: cdk.RemovalPolicy.DESTROY, // Important:  For testing, use DESTROY.  For production, consider REPLICA or RETENTION.
      autoDeleteObjects: true, // Automatically delete objects after 30 days
      versioningConfiguration: s3.VersionConfiguration.SUSPENDED, // Enable versioning
    });

    // Configure Bucket Policy (Example - Restrict access to specific IAM roles)
    const adminRole = new iam.Role(this, 'AdminRole', {
      assumedBy: iam.ServicePrincipal('cdk.us-east-1.amazonaws.com'), // CDK execution role
    });

    bucket.addToBucketPolicy(
      `
        {
          "Version": "2012-10-17",
          "Statement": [
            {
              "Sid": "AllowCDKAdminAccess",
              "Effect": "Allow",
              "Principal": {
                "Service": "cdk.us-east-1.amazonaws.com"
              },
              "Action": [
                "s3:GetObject",
                "s3:PutObject",
                "s3:DeleteObject",
                "s3:ListBucket"
              ],
              "Resource": [
                "arn:aws:s3:::customer-financial-records-" + this.node.id,
                "arn:aws:s3:::customer-financial-records-" + this.node.id + "/*"
              ]
            }
          ]
        }
      `
    );

    // Enable server-side encryption
    bucket.grantReadWrite(adminRole); // Grant the admin role permission to read and write

    // Output the bucket name
    new cdk.CfnOutput(this, 'BucketName', {
      value: bucket.bucketName,
    });
  }
}

